#!/usr/bin/env python3
"""Scan FSMRepairBench and regenerate API, CLI, and schema documentation."""

from __future__ import annotations

import argparse
import importlib
import inspect
import pkgutil
import sys
from collections.abc import Sequence
from dataclasses import dataclass
from pathlib import Path
from typing import Any

import typer
from pydantic import BaseModel
from pydantic.fields import FieldInfo

REPO_ROOT = Path(__file__).resolve().parents[1]
SRC_ROOT = REPO_ROOT / "src"
DOCS_DIR = REPO_ROOT / "docs"
GENERATED_HEADER = (
    "<!-- Generated by scripts/update_docs.py. Do not edit manually. -->\n\n"
)

OUTPUT_FILES = {
    "api": DOCS_DIR / "api.md",
    "cli": DOCS_DIR / "cli.md",
    "schemas": DOCS_DIR / "schemas.md",
}

CASE_METADATA_FIELDS: tuple[tuple[str, str, str], ...] = (
    ("case_id", "string", "Stable case identifier (`case_{index:06d}`)"),
    ("benchmark_version", "string", "Schema version for the case"),
    ("reference_fsm_id", "string", "Reference FSM identifier"),
    ("faulty_fsm_id", "string", "Faulty FSM identifier"),
    ("complexity", "string", "Synthetic complexity preset"),
    ("state_count", "integer", "Reachable state count"),
    ("transition_count", "integer", "Reachable transition count"),
    ("event_count", "integer", "Event alphabet size"),
    ("mutation_operator", "string", "Applied mutation operator"),
    ("difficulty_score", "float", "Structural difficulty score (0–100)"),
    ("difficulty_category", "string", "easy | medium | hard | expert"),
    ("difficulty", "object", "Full difficulty metadata block"),
    ("oracle_coverage", "object", "state/transition/event coverage ratios"),
    ("reference_bpr", "float", "Reference FSM behavioural pass rate"),
    ("faulty_bpr", "float", "Faulty FSM behavioural pass rate"),
    ("bpr_delta", "float", "reference_bpr - faulty_bpr"),
    ("valid_reference", "boolean", "Reference FSM passed validation"),
    ("valid_faulty", "boolean", "Faulty FSM passed validation"),
)

PATH_PLACEHOLDERS: dict[str, str] = {
    "path": "tests/fixtures/valid_fsm.json",
    "fsm_path": "tests/fixtures/valid_fsm.json",
    "ref_fsm_path": "tests/fixtures/valid_fsm.json",
    "oracle_path": "tests/fixtures/valid_oracle.json",
    "patch_path": "patch.json",
    "dataset_dir": "DATASET_DIR",
    "output_dir": "OUTPUT_DIR",
    "results_dir": "RESULTS_DIR",
    "release_dir": "RELEASE_DIR",
    "input_dir": "RESULTS_DIR",
    "case_path": "cases/case_000001",
    "plan_path": "plans/fsmrepairbench_v0_10k_plan.yaml",
    "source_dir": "DATASET_A",
    "target_dir": "DATASET_B",
    "artifact_dir": "artifacts/icse2027",
    "config_path": "configs/experiment.yaml",
}


@dataclass(frozen=True)
class CliParam:
    name: str
    type_name: str
    optional: bool
    flags: tuple[str, ...]
    default: Any
    help_text: str | None


@dataclass(frozen=True)
class CliCommand:
    name: str
    summary: str
    params: tuple[CliParam, ...]


@dataclass(frozen=True)
class ModelInfo:
    module: str
    name: str
    cls: type[BaseModel]


def _ensure_import_path() -> None:
    src = str(SRC_ROOT)
    if src not in sys.path:
        sys.path.insert(0, src)


def _type_name(annotation: Any) -> str:
    if annotation is inspect._empty:
        return "Any"
    if isinstance(annotation, type):
        return annotation.__name__
    return str(annotation).replace("typing.", "").replace("pathlib.", "")


def _default_repr(value: Any) -> str:
    if value is inspect._empty or value is ...:
        return "required"
    if isinstance(value, Path):
        return str(value)
    if hasattr(value, "value"):
        return str(value.value)
    return repr(value)


def _extract_typer_param(name: str, param: inspect.Parameter) -> CliParam:
    default = param.default
    optional = False
    flags: tuple[str, ...] = ()
    help_text: str | None = None

    if isinstance(default, typer.models.OptionInfo):
        optional = True
        flags = tuple(default.param_decls or ())
        help_text = default.help
        default = default.default
    elif isinstance(default, typer.models.ArgumentInfo):
        flags = tuple(default.param_decls or ())
        help_text = default.help
        default = default.default

    return CliParam(
        name=name,
        type_name=_type_name(param.annotation),
        optional=optional,
        flags=flags,
        default=default,
        help_text=help_text,
    )


def _command_from_callback(name: str, callback: Any) -> CliCommand:
    summary = (callback.__doc__ or "").strip().split("\n")[0]
    params = tuple(
        _extract_typer_param(param_name, param)
        for param_name, param in inspect.signature(callback).parameters.items()
    )
    return CliCommand(name=name, summary=summary, params=params)


def discover_cli_commands() -> list[CliCommand]:
    """Collect CLI commands from the Typer application."""
    _ensure_import_path()
    from fsmrepairbench.cli import app

    commands: list[CliCommand] = []
    for command_info in app.registered_commands:
        commands.append(_command_from_callback(command_info.name or "", command_info.callback))

    for group in app.registered_groups:
        prefix = group.name or ""
        for command_info in group.typer_instance.registered_commands:
            command_name = command_info.name or ""
            full_name = f"{prefix} {command_name}".strip()
            command = _command_from_callback(full_name, command_info.callback)
            commands.append(command)

    return sorted(commands, key=lambda item: item.name)


def discover_pydantic_models() -> list[ModelInfo]:
    """Import package modules and collect concrete Pydantic model classes."""
    _ensure_import_path()
    import fsmrepairbench

    models: list[ModelInfo] = []
    seen: set[tuple[str, str]] = set()

    for module_info in pkgutil.walk_packages(fsmrepairbench.__path__, fsmrepairbench.__name__ + "."):
        module = importlib.import_module(module_info.name)
        for obj_name, obj in inspect.getmembers(module, inspect.isclass):
            if obj is BaseModel or not issubclass(obj, BaseModel):
                continue
            if obj.__module__ != module_info.name:
                continue
            key = (module_info.name, obj_name)
            if key in seen:
                continue
            seen.add(key)
            models.append(ModelInfo(module=module_info.name, name=obj_name, cls=obj))

    return sorted(models, key=lambda item: (item.module, item.name))


def discover_benchmark_schemas() -> dict[str, Any]:
    """Load benchmark version specifications."""
    _ensure_import_path()
    from fsmrepairbench.versioning import VERSION_SPECS

    return {
        version.value: {
            "dataset_id": spec.dataset_id,
            "required_case_files": list(spec.required_case_files),
            "optional_case_files": list(spec.optional_case_files),
            "metadata_fields": list(spec.metadata_fields),
            "compatible_read_versions": [item.value for item in spec.compatible_read_versions],
        }
        for version, spec in VERSION_SPECS.items()
    }


def _field_type(field: FieldInfo) -> str:
    annotation = field.annotation
    if annotation is None:
        return "Any"
    return _type_name(annotation)


def _field_description(model: type[BaseModel], field_name: str, field: FieldInfo) -> str:
    if field.description:
        return field.description
    json_schema = model.model_json_schema()
    properties = json_schema.get("properties", {})
    property_schema = properties.get(field_name, {})
    if isinstance(property_schema, dict) and property_schema.get("description"):
        return str(property_schema["description"])
    return ""


def _render_fields_table(model: type[BaseModel]) -> list[str]:
    lines = ["| Field | Type | Required | Default | Description |", "|-------|------|----------|---------|-------------|"]
    for field_name, field in model.model_fields.items():
        required = "yes" if field.is_required() else "no"
        default = _default_repr(field.default) if not field.is_required() else "—"
        description = _field_description(model, field_name, field).replace("|", "\\|")
        lines.append(
            f"| `{field_name}` | `{_field_type(field)}` | {required} | {default} | {description} |"
        )
    return lines


def _render_model_section(model_info: ModelInfo) -> list[str]:
    model = model_info.cls
    summary = (model.__doc__ or "Pydantic model.").strip()
    lines = [
        f"### `{model_info.name}`",
        "",
        f"Module: `{model_info.module}`",
        "",
        summary,
        "",
        *_render_fields_table(model),
        "",
    ]
    return lines


def render_api_md(models: Sequence[ModelInfo]) -> str:
    lines = [
        GENERATED_HEADER.rstrip(),
        "",
        "# API Reference",
        "",
        "Pydantic models discovered under `src/fsmrepairbench/`.",
        "",
    ]

    by_module: dict[str, list[ModelInfo]] = {}
    for model in models:
        by_module.setdefault(model.module, []).append(model)

    for module in sorted(by_module):
        lines.extend([f"## `{module}`", ""])
        for model in by_module[module]:
            lines.extend(_render_model_section(model))

    return "\n".join(lines).rstrip() + "\n"


def _example_value(param: CliParam) -> str | None:
    if param.name in PATH_PLACEHOLDERS:
        return PATH_PLACEHOLDERS[param.name]
    if param.type_name == "int":
        return "42"
    if param.type_name == "str":
        if param.name == "operator":
            return "missing_transition"
        if param.name == "bucket_method":
            return "quantile"
        return "VALUE"
    if param.type_name == "float":
        return "0.85"
    if param.type_name == "bool":
        return None
    if "Path" in param.type_name:
        return PATH_PLACEHOLDERS.get(param.name, "PATH")
    if param.default not in (inspect._empty, ..., None) and not param.optional:
        return _default_repr(param.default)
    return None


def _usage_example(command: CliCommand) -> str:
    parts = ["fsmrepairbench", *command.name.split()]
    for param in command.params:
        if param.optional:
            if param.default in (inspect._empty, ..., None):
                if param.flags and param.name in {"operator", "seed", "out", "meta", "size"}:
                    value = _example_value(param)
                    if value and param.flags:
                        parts.append(f"{param.flags[0].split('/')[0]} {value}")
                continue
            continue
        value = _example_value(param)
        if value is not None:
            parts.append(value)
    return " ".join(parts)


def _params_table(params: Sequence[CliParam]) -> list[str]:
    if not params:
        return ["_No parameters._", ""]
    lines = ["| Parameter | Type | Flags | Default | Description |", "|-----------|------|-------|---------|-------------|"]
    for param in params:
        flags = ", ".join(f"`{flag}`" for flag in param.flags) if param.flags else "positional"
        description = (param.help_text or "").replace("|", "\\|")
        lines.append(
            f"| `{param.name}` | `{param.type_name}` | {flags} | {_default_repr(param.default)} | {description} |"
        )
    return lines


def render_cli_md(commands: Sequence[CliCommand]) -> str:
    lines = [
        GENERATED_HEADER.rstrip(),
        "",
        "# CLI Reference",
        "",
        "Commands registered in `fsmrepairbench.cli`.",
        "",
        "## Quick start",
        "",
        "```bash",
        "fsmrepairbench --help",
        "fsmrepairbench validate-fsm tests/fixtures/valid_fsm.json",
        "fsmrepairbench build-dataset --size 10 --seed 42 --output OUTPUT_DIR",
        "```",
        "",
        "## Commands",
        "",
    ]

    for command in commands:
        lines.extend(
            [
                f"### `{command.name}`",
                "",
                command.summary,
                "",
                "**Usage**",
                "",
                "```bash",
                _usage_example(command),
                "```",
                "",
                *_params_table(command.params),
                "",
            ]
        )

    return "\n".join(lines).rstrip() + "\n"


def render_schemas_md(
    models: Sequence[ModelInfo],
    benchmark_schemas: dict[str, Any],
) -> str:
    core_names = {
        "FSM",
        "State",
        "Transition",
        "OracleSuite",
        "OracleScenario",
        "OracleStep",
        "BugMetadata",
        "FSMPatch",
        "ExperimentConfig",
    }
    core_models = [model for model in models if model.name in core_names]

    lines = [
        GENERATED_HEADER.rstrip(),
        "",
        "# Schema Reference",
        "",
        "Benchmark on-disk schemas and version specifications.",
        "",
        "## Benchmark versions",
        "",
        "| Version | Dataset ID | Required case files | Optional case files |",
        "|---------|------------|---------------------|---------------------|",
    ]

    for version, spec in sorted(benchmark_schemas.items()):
        required = ", ".join(f"`{name}`" for name in spec["required_case_files"])
        optional = ", ".join(f"`{name}`" for name in spec["optional_case_files"]) or "—"
        lines.append(f"| `{version}` | `{spec['dataset_id']}` | {required} | {optional} |")

    lines.extend(["", "## Dataset metadata fields", ""])
    for version, spec in sorted(benchmark_schemas.items()):
        fields = ", ".join(f"`{field}`" for field in spec["metadata_fields"])
        lines.extend([f"### `{version}`", "", fields, ""])

    lines.extend(["", "## Case metadata (`case_metadata.json`)", ""])
    lines.extend(
        [
            "| Field | Type | Description |",
            "|-------|------|-------------|",
        ]
    )
    for field_name, field_type, description in CASE_METADATA_FIELDS:
        lines.append(f"| `{field_name}` | {field_type} | {description} |")

    lines.extend(["", "## Core JSON models", ""])
    for model in core_models:
        lines.extend(_render_model_section(model))

    lines.extend(
        [
            "## Validation",
            "",
            "```bash",
            "fsmrepairbench validate-fsm tests/fixtures/valid_fsm.json",
            "fsmrepairbench validate-oracle tests/fixtures/valid_oracle.json",
            "fsmrepairbench validate-dataset DATASET_DIR",
            "fsmrepairbench benchmark-version DATASET_DIR",
            "```",
            "",
        ]
    )

    return "\n".join(lines).rstrip() + "\n"


def generate_docs() -> dict[str, str]:
    models = discover_pydantic_models()
    commands = discover_cli_commands()
    benchmark_schemas = discover_benchmark_schemas()
    return {
        "api": render_api_md(models),
        "cli": render_cli_md(commands),
        "schemas": render_schemas_md(models, benchmark_schemas),
    }


def write_docs(docs: dict[str, str]) -> None:
    DOCS_DIR.mkdir(parents=True, exist_ok=True)
    for key, path in OUTPUT_FILES.items():
        path.write_text(docs[key], encoding="utf-8")


def docs_are_current(docs: dict[str, str]) -> bool:
    for key, path in OUTPUT_FILES.items():
        if not path.is_file():
            return False
        if path.read_text(encoding="utf-8") != docs[key]:
            return False
    return True


def parse_args(argv: Sequence[str] | None = None) -> argparse.Namespace:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument(
        "--check",
        action="store_true",
        help="Exit with code 1 if generated docs differ from files on disk.",
    )
    return parser.parse_args(argv)


def main(argv: Sequence[str] | None = None) -> int:
    args = parse_args(argv)
    docs = generate_docs()
    if args.check:
        if docs_are_current(docs):
            return 0
        print("Documentation is out of date. Run: python scripts/update_docs.py", file=sys.stderr)
        return 1

    write_docs(docs)
    for path in OUTPUT_FILES.values():
        print(f"Wrote {path}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
